#!/usr/bin/env python
"""
Bootstrap: Colloidal Acoustic Absorption Model (Multi-Physics Phase 2)
Writes core/colloidal_acoustic.py + tests/test_colloidal_acoustic.py
No dependencies on other MABE modules.
Run: python bootstrap_colloidal_acoustic.py
"""
import base64, os, sys

if os.path.exists("core/universal_schema.py"): root = "."
elif os.path.exists("../core/universal_schema.py"): root = ".."
else: print("ERROR: Run from MABE root or one dir below."); sys.exit(1)

_p = os.path.join(root, "core/colloidal_acoustic.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

_p = os.path.join(root, "tests/test_colloidal_acoustic.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

print("Done. Run: python -m pytest tests/test_colloidal_acoustic.py -v")